func (q *Queries) MarkMessagesCompacted(ctx context.Context, arg MarkMessagesCompactedParams) error {
	query := markMessagesCompacted
	var queryParams []interface{}
	queryParams = append(queryParams, arg.CompactID)
	if len(arg.Ids) > 0 {
		for _, v := range arg.Ids {
			queryParams = append(queryParams, v)
		}
		query = strings.Replace(query, "/*SLICE:ids*/?", strings.Repeat(",?", len(arg.Ids))[1:], 1)
	} else {
		query = strings.Replace(query, "/*SLICE:ids*/?", "NULL", 1)
	}
	_, err := q.db.ExecContext(ctx, query, queryParams...)
	return err
}

const searchMessages = `-- name: SearchMessages :many
SELECT
  m.id, m.bot_id, m.session_id, m.sender_channel_identity_id,
  m.branch_id, m.branch_seq,
  m.role, m.content, m.created_at,
  ci.display_name AS sender_display_name,
  s.channel_type AS platform
FROM bot_history_messages m
LEFT JOIN channel_identities ci ON ci.id = m.sender_channel_identity_id
LEFT JOIN bot_sessions s ON s.id = m.session_id
WHERE m.bot_id = ?1
  AND (?2 IS NULL OR m.session_id = ?2)
  AND (?3 IS NULL OR m.sender_channel_identity_id = ?3)
  AND (?4 IS NULL OR m.created_at >= strftime('%Y-%m-%d %H:%M:%S', ?4))
  AND (?5 IS NULL OR m.created_at <= strftime('%Y-%m-%d %H:%M:%S', ?5))
  AND (?6 IS NULL OR m.role = ?6)
  AND (?7 IS NULL OR (
    CASE
      WHEN NOT json_valid(m.content)
        THEN CASE WHEN m.content LIKE '%' || ?7 || '%' THEN m.content ELSE '' END
      WHEN json_valid(m.content) AND json_type(m.content, '$.content') = 'text'
        THEN json_extract(m.content, '$.content')
      WHEN json_valid(m.content) AND json_type(m.content, '$.content') = 'array'
        THEN (SELECT COALESCE(group_concat(json_extract(j.value, '$.text'), ' '), '')
              FROM json_each(
                CASE
                  WHEN json_valid(m.content) AND json_type(m.content, '$.content') = 'array'
                    THEN json_extract(m.content, '$.content')
                  ELSE '[]'
                END
              ) AS j
              WHERE json_valid(j.value) AND json_extract(j.value, '$.type') = 'text')
      ELSE ''
    END
  ) LIKE '%' || ?7 || '%')
ORDER BY m.created_at DESC
LIMIT ?8
`

type SearchMessagesParams struct {
	BotID     string      `json:"bot_id"`
	SessionID interface{} `json:"session_id"`
	ContactID interface{} `json:"contact_id"`
	StartTime interface{} `json:"start_time"`
	EndTime   interface{} `json:"end_time"`
	Role      interface{} `json:"role"`
	Keyword   interface{} `json:"keyword"`
	MaxCount  int64       `json:"max_count"`
}

type SearchMessagesRow struct {
	ID                      string         `json:"id"`
	BotID                   string         `json:"bot_id"`
	SessionID               sql.NullString `json:"session_id"`
	SenderChannelIdentityID sql.NullString `json:"sender_channel_identity_id"`
	BranchID                sql.NullString `json:"branch_id"`
	BranchSeq               sql.NullInt64  `json:"branch_seq"`
	Role                    string         `json:"role"`
	Content                 string         `json:"content"`
	CreatedAt               string         `json:"created_at"`
	SenderDisplayName       sql.NullString `json:"sender_display_name"`
	Platform                sql.NullString `json:"platform"`
}

func (q *Queries) SearchMessages(ctx context.Context, arg SearchMessagesParams) ([]SearchMessagesRow, error) {
	rows, err := q.db.QueryContext(ctx, searchMessages,
		arg.BotID,
		arg.SessionID,
		arg.ContactID,
		arg.StartTime,
		arg.EndTime,
		arg.Role,
		arg.Keyword,
		arg.MaxCount,
	)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var items []SearchMessagesRow
	for rows.Next() {
		var i SearchMessagesRow
		if err := rows.Scan(
			&i.ID,
			&i.BotID,
			&i.SessionID,
			&i.SenderChannelIdentityID,
			&i.BranchID,
			&i.BranchSeq,
			&i.Role,
			&i.Content,
			&i.CreatedAt,
			&i.SenderDisplayName,
			&i.Platform,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Close(); err != nil {
		return nil, err
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

const setActiveSessionBranch = `-- name: SetActiveSessionBranch :execrows
UPDATE bot_sessions
SET active_branch_id = ?1,
    updated_at = CURRENT_TIMESTAMP
WHERE bot_sessions.id = ?2
  AND EXISTS (
    SELECT 1
    FROM bot_session_branches b
    WHERE b.id = ?1
      AND b.session_id = ?2
  )
`

type SetActiveSessionBranchParams struct {
	BranchID  sql.NullString `json:"branch_id"`
	SessionID string         `json:"session_id"`
}

func (q *Queries) SetActiveSessionBranch(ctx context.Context, arg SetActiveSessionBranchParams) (int64, error) {
	result, err := q.db.ExecContext(ctx, setActiveSessionBranch, arg.BranchID, arg.SessionID)
	if err != nil {
		return 0, err
	}
	return result.RowsAffected()
}

